1	/** A live cell's coordinates as [x, y]. */
2	export type Cell = [number, number];
3	
4	/**
5	 * Returns the next generation of live cells per Conway's Game of Life rules.
6	 *
7	 * Rules:
8	 *  - Underpopulation: a live cell with fewer than 2 live neighbors dies.
9	 *  - Survival: a live cell with 2 or 3 live neighbors lives on.
10	 *  - Overpopulation: a live cell with more than 3 live neighbors dies.
11	 *  - Reproduction: a dead cell with exactly 3 live neighbors becomes alive.
12	 */
13	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
14	  [-1, -1], [-1, 0], [-1, 1],
15	  [ 0, -1],          [ 0, 1],
16	  [ 1, -1], [ 1, 0], [ 1, 1],
17	];
18	
19	const toKey = ([x, y]: Cell): string => `${x},${y}`;
20	
21	const isAliveNextGeneration = (isCurrentlyAlive: boolean, liveNeighborCount: number): boolean =>
22	  liveNeighborCount === 3 || (isCurrentlyAlive && liveNeighborCount === 2);
23	
24	export function nextGeneration(liveCells: Cell[]): Cell[] {
25	  const liveSet = new Set(liveCells.map(toKey));
26	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
27	
28	  for (const [x, y] of liveCells) {
29	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
30	      const neighbor: Cell = [x + dx, y + dy];
31	      const key = toKey(neighbor);
32	      const entry = neighborCounts.get(key);
33	      if (entry) entry.count++;
34	      else neighborCounts.set(key, { cell: neighbor, count: 1 });
35	    }
36	  }
37	
38	  const nextLiveCells: Cell[] = [];
39	  for (const { cell, count } of neighborCounts.values()) {
40	    if (isAliveNextGeneration(liveSet.has(toKey(cell)), count)) {
41	      nextLiveCells.push(cell);
42	    }
43	  }
44	  return nextLiveCells;
45	}
